## Complete Examples

### Generic Container

```aria
struct Vec<T> {
    data: []T,
    len: usize,
    capacity: usize
}

impl<T> Vec<T> {
    fn new() -> Vec<T> {
        return Vec{
            data: [],
            len: 0,
            capacity: 0
        };
    }

    fn push(item: T) {
        // Implementation
    }

    fn get(index: usize) -> T? {
        when index >= self.len then
            return nil;
        end
        return self.data[index];
    }
}

// Usage
numbers: Vec<i32> = Vec::new();
