extern func:aria_atomic_int32_create = wild int8*(int32:initial_value);
extern func:aria_atomic_int32_destroy = void(wild int8*:atomic_ptr);
extern func:aria_atomic_int32_store = void(wild int8*:atomic_ptr, int32:value, int32:order);
extern func:aria_atomic_int32_load = int32(wild int8*:atomic_ptr, int32:order);
extern func:aria_atomic_int32_fetch_add = int32(wild int8*:atomic_ptr, int32:value, int32:order);

func:main = int32() {
