    // Load with SEQ_CST (4)
    int32:value = aria_atomic_int32_load(atomic_ptr, 4);

    // Add 10
    int32:old = aria_atomic_int32_fetch_add(atomic_ptr, 10, 4);

    // Load again
    int32:new_value = aria_atomic_int32_load(atomic_ptr, 4);

    // Cleanup - explicitly discard result
    _ = aria_atomic_int32_destroy(atomic_ptr);

    // Check results: value should be 42, old should be 42, new_value should be 52
    if (value == 42 && old == 42 && new_value == 52) {
        pass(0);  // SUCCESS
    } else {
        pass(1);  // FAIL
    }
};

func:failsafe = NIL(int32:err_code) {
    // Error handling
    pass(NIL);
};

