## Real-World Examples

### Generic Cache

```aria
struct Cache<K, V> {
    data: Map<K, V>,
    max_size: usize
}

impl<K, V> Cache<K, V> where K: Hashable {
    fn new(max_size: usize) -> Cache<K, V> {
        return Cache{
            data: Map::new(),
            max_size: max_size
        };
    }

    fn get(key: K) -> V? {
        return self.data.get(key);
    }

    fn set(key: K, value: V) {
        when self.data.len() >= self.max_size then
            self.evict_oldest();
        end
        self.data.insert(key, value);
    }
}

// Usage
user_cache: Cache<i32, User> = Cache::new(100);
session_cache: Cache<string, Session> = Cache::new(1000);
```

### Generic Builder

```aria
struct Builder<T> {
    items: []T,
    validators: []fn(T) -> bool
}

impl<T> Builder<T> {
    fn new() -> Builder<T> {
        return Builder{
            items: [],
            validators: []
        };
    }

    fn add(item: T) -> Builder<T> {
        till(self.validators.length - 1, 1) {
            validator: fn(T) -> bool = self.validators[$];
            when !validator(item) then
                panic("Validation failed");
            end
        }
        self.items.push(item);
        return self;
    }

    fn validate(f: fn(T) -> bool) -> Builder<T> {
        self.validators.push(f);
        return self;
    }

    fn build() -> []T {
        return self.items;
    }
```

### Generic Tree

```aria
struct Tree<T> {
    value: T,
    left: Box<Tree<T>>?,
    right: Box<Tree<T>>?
}

impl<T> Tree<T> {
    fn leaf(value: T) -> Tree<T> {
        return Tree{
            value: value,
            left: nil,
            right: nil
        };
    }

    fn insert(value: T) where T: Comparable {
        when value < self.value then
            when self.left == nil then
                self.left = Some(Box::new(Tree::leaf(value)));
            else
                self.left.unwrap().insert(value);
            end
        else
            // Insert right
        end
    }
```

