uint32:withdrawal = 5000u32;

?uint32:new_balance = safe_subtract_u32(balance, withdrawal);

if (new_balance == NIL) {
    stderr.write("Insufficient funds!\n");
} else {
    log.write("New balance: "); new_balance.write_to(log); log.write("\n");
```

